package genxsolution.vms.vmsbackend.maintenance_management.repair_job.repository;
import genxsolution.vms.vmsbackend.maintenance_management.repair_job.dto.RepairJobUpsertRequest; import genxsolution.vms.vmsbackend.maintenance_management.repair_job.model.RepairJob; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.stereotype.Repository; import java.sql.*; import java.util.*;
@Repository public class RepairJobRepository { private final JdbcTemplate jdbcTemplate; public RepairJobRepository(JdbcTemplate jdbcTemplate){this.jdbcTemplate=jdbcTemplate;}
public List<RepairJob> findAll(UUID companyId){ String sql="SELECT repair_job_id, company_id, company_code, breakdown_id, repair_type_id, diagnosis_notes, decided_solution, estimated_cost, actual_cost, start_date, completion_date, status_id, created_by, created_at, updated_at FROM repair_job "+(companyId==null?"":"WHERE company_id = ? ")+"ORDER BY updated_at DESC"; return companyId==null?jdbcTemplate.query(sql,this::mapRow):jdbcTemplate.query(sql,this::mapRow,companyId); }
public Optional<RepairJob> findById(UUID id){ return jdbcTemplate.query("SELECT repair_job_id, company_id, company_code, breakdown_id, repair_type_id, diagnosis_notes, decided_solution, estimated_cost, actual_cost, start_date, completion_date, status_id, created_by, created_at, updated_at FROM repair_job WHERE repair_job_id = ?", this::mapRow, id).stream().findFirst(); }
public RepairJob create(RepairJobUpsertRequest r){ String sql="""
INSERT INTO repair_job (company_id, company_code, breakdown_id, repair_type_id, diagnosis_notes, decided_solution, estimated_cost, actual_cost, start_date, completion_date, status_id, created_by, updated_at)
VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
RETURNING repair_job_id, company_id, company_code, breakdown_id, repair_type_id, diagnosis_notes, decided_solution, estimated_cost, actual_cost, start_date, completion_date, status_id, created_by, created_at, updated_at
"""; return jdbcTemplate.queryForObject(sql,this::mapRow,r.companyId(),r.companyCode(),r.breakdownId(),r.repairTypeId(),r.diagnosisNotes(),r.decidedSolution(),r.estimatedCost(),r.actualCost(),r.startDate(),r.completionDate(),r.statusId(),r.createdBy(),r.updatedAt()); }
public Optional<RepairJob> update(UUID id,RepairJobUpsertRequest r){ String sql="""
UPDATE repair_job SET company_id = COALESCE(?, company_id), company_code = COALESCE(?, company_code), breakdown_id = COALESCE(?, breakdown_id), repair_type_id = COALESCE(?, repair_type_id), diagnosis_notes = COALESCE(?, diagnosis_notes), decided_solution = COALESCE(?, decided_solution), estimated_cost = COALESCE(?, estimated_cost), actual_cost = COALESCE(?, actual_cost), start_date = COALESCE(?, start_date), completion_date = COALESCE(?, completion_date), status_id = COALESCE(?, status_id), created_by = COALESCE(?, created_by), updated_at = COALESCE(?, updated_at)
WHERE repair_job_id = ?
RETURNING repair_job_id, company_id, company_code, breakdown_id, repair_type_id, diagnosis_notes, decided_solution, estimated_cost, actual_cost, start_date, completion_date, status_id, created_by, created_at, updated_at
"""; return jdbcTemplate.query(sql,this::mapRow,r.companyId(),r.companyCode(),r.breakdownId(),r.repairTypeId(),r.diagnosisNotes(),r.decidedSolution(),r.estimatedCost(),r.actualCost(),r.startDate(),r.completionDate(),r.statusId(),r.createdBy(),r.updatedAt(),id).stream().findFirst(); }
public boolean delete(UUID id){ return jdbcTemplate.update("DELETE FROM repair_job WHERE repair_job_id = ?", id)>0; }
private RepairJob mapRow(ResultSet rs,int n)throws SQLException{ java.sql.Date startDateDate=rs.getDate("start_date"); java.sql.Date completionDateDate=rs.getDate("completion_date"); Timestamp createdAtTs=rs.getTimestamp("created_at"); Timestamp updatedAtTs=rs.getTimestamp("updated_at"); return new RepairJob(rs.getObject("repair_job_id",UUID.class),rs.getObject("company_id",UUID.class),rs.getString("company_code"),rs.getObject("breakdown_id",UUID.class),rs.getObject("repair_type_id",Integer.class),rs.getString("diagnosis_notes"),rs.getString("decided_solution"),rs.getBigDecimal("estimated_cost"),rs.getBigDecimal("actual_cost"),startDateDate==null?null:startDateDate.toLocalDate(),completionDateDate==null?null:completionDateDate.toLocalDate(),rs.getObject("status_id",Integer.class),rs.getObject("created_by",UUID.class),createdAtTs==null?null:createdAtTs.toInstant(),updatedAtTs==null?null:updatedAtTs.toInstant()); }
}
